B.and=new A.iB("\uc27c\uc744 \uc8fc\uc2dc\ub294 \uc608\uc218\ub2d8","\uc218\uace0\ud558\uace0 \ubb34\uac70\uc6b4 \uc9d0 \uc9c4 \uc790\ub4e4\uc544\n\ub2e4 \ub0b4\uac8c\ub85c \uc624\ub77c\n\ub0b4\uac00 \ub108\ud76c\ub97c \uc26c\uac8c \ud558\ub9ac\ub77c","\ub9c8\ud0dc\ubcf5\uc74c 11:28","\uc9c0\uae08 \ub2f9\uc2e0\uc774 \uc9ca\uc5b4\uc9c0\uace0 \uc788\ub294 \ubb34\uac70\uc6b4 \uc9d0\uc740 \ubb34\uc5c7\uc778\uac00\uc694?\n\uc608\uc218\ub2d8\uc740 \uadf8 \uc9d0\uc744 \ub300\uc2e0 \uc838\uc8fc\uaca0\ub2e4\uace0 \ud558\uc2ed\ub2c8\ub2e4.\n\uc624\ub298 \ud558\ub8e8, \uadf8 \uc9d0\uc744 \uc608\uc218\ub2d8\uaed8 \ub0b4\ub824\ub193\ub294 \uc5f0\uc2b5\uc744 \ud574\ubcf4\uc138\uc694.")
B.ane=new A.iB("\uc5fc\ub824\ub97c \ub9e1\uae30\ub294 \uc0b6","\ub108\ud76c \uc5fc\ub824\ub97c \ub2e4 \uc8fc\uaed8 \ub9e1\uae30\ub77c\n\uc774\ub294 \uadf8\uac00 \ub108\ud76c\ub97c \ub3cc\ubcf4\uc2ec\uc774\ub77c","\ubca0\ub4dc\ub85c\uc804\uc11c 5:7",'\uc624\ub298 \ub9c8\uc74c\uc5d0 \uac78\ub9ac\ub294 \uc5fc\ub824\uac00 \uc788\ub098\uc694?\n\ud558\ub098\ub2d8\uc740 \uc6b0\ub9ac\uc758 \uc791\uc740 \uc5fc\ub824\uae4c\uc9c0\ub3c4 \uad00\uc2ec\uc744 \uac00\uc9c0\uace0 \uacc4\uc2ed\ub2c8\ub2e4.\n"\uadf8\uac00 \ub108\ud76c\ub97c \ub3cc\ubcf4\uc2ec\uc774\ub77c"\ub294 \ub9d0\uc500\uc744 \ub9c8\uc74c\uc5d0 \uc0c8\uaca8\ubcf4\uc138\uc694.')
B.ana=new A.iB("\ud569\ub825\ud558\uc5ec \uc120\uc744 \uc774\ub8e8\uc2ec","\uc6b0\ub9ac\uac00 \uc54c\uac70\ub2c8\uc640 \ud558\ub098\ub2d8\uc744 \uc0ac\ub791\ud558\ub294 \uc790\n\uace7 \uadf8\uc758 \ub73b\ub300\ub85c \ubd80\ub974\uc2ec\uc744 \uc785\uc740 \uc790\ub4e4\uc5d0\uac8c\ub294\n\ubaa8\ub4e0 \uac83\uc774 \ud569\ub825\ud558\uc5ec \uc120\uc744 \uc774\ub8e8\ub290\ub2c8\ub77c","\ub85c\ub9c8\uc11c 8:28","\uc9c0\uae08\uc740 \uc774\ud574\ub418\uc9c0 \uc54a\ub294 \uc0c1\ud669\uc774 \uc788\ub098\uc694?\n\ud558\ub098\ub2d8\uc740 \ubaa8\ub4e0 \uac83\uc744 \ud569\ub825\ud558\uc5ec \uc120\uc744 \uc774\ub8e8\uc2ed\ub2c8\ub2e4.\n\ud604\uc7ac\uc758 \uc5b4\ub824\uc6c0\ub3c4 \ud558\ub098\ub2d8\uc758 \ud070 \uadf8\ub9bc \uc548\uc5d0 \uc788\uc74c\uc744 \uae30\uc5b5\ud574\ubcf4\uc138\uc694.")
B.anc=new A.iB("\uc0c8 \ud798\uc744 \uc5bb\ub294 \uc790","\uc624\uc9c1 \uc5ec\ud638\uc640\ub97c \uc559\ub9dd\ud558\ub294 \uc790\ub294 \uc0c8 \ud798\uc744 \uc5bb\uc73c\ub9ac\ub2c8\n\ub3c5\uc218\ub9ac\uac00 \ub0a0\uac1c\uce58\uba70 \uc62c\ub77c\uac10 \uac19\uc744 \uac83\uc774\uc694\n\ub2ec\uc74c\ubc15\uc9c8\ud558\uc5ec\ub3c4 \uace4\ube44\ud558\uc9c0 \uc544\ub2c8\ud558\uaca0\uace0\n\uac78\uc5b4\uac00\ub3c4 \ud53c\uace4\ud558\uc9c0 \uc544\ub2c8\ud558\ub9ac\ub85c\ub2e4","\uc774\uc0ac\uc57c 40:31","\uc9c0\uce58\uace0 \ud798\uc774 \ube60\uc9c4 \ub0a0\uc774 \uc788\ub098\uc694?\n\ud558\ub098\ub2d8\uc744 \uc559\ub9dd(\ubc14\ub77c\ubd04)\ud558\ub294 \uac83\ub9cc\uc73c\ub85c\ub3c4 \uc0c8 \ud798\uc744 \uc5bb\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\n\uc624\ub298 \uc7a0\uc2dc \uba48\ucd94\uace0, \ud558\ub098\ub2d8\uc744 \ubc14\ub77c\ubcf4\ub294 \uc2dc\uac04\uc744 \uac00\uc838\ubcf4\uc138\uc694.")
B.an9=new A.iB("\uae38\uc774\uc694 \uc9c4\ub9ac\uc694 \uc0dd\uba85","\uc608\uc218\uaed8\uc11c \uc774\ub974\uc2dc\ub418\n\ub0b4\uac00 \uace7 \uae38\uc774\uc694 \uc9c4\ub9ac\uc694 \uc0dd\uba85\uc774\ub2c8\n\ub098\ub85c \ub9d0\ubbf8\uc554\uc9c0 \uc54a\uace0\ub294\n\uc544\ubc84\uc9c0\uaed8\ub85c \uc62c \uc790\uac00 \uc5c6\ub290\ub2c8\ub77c","\uc694\ud55c\ubcf5\uc74c 14:6",'\uc778\uc0dd\uc5d0\uc11c \uae38\uc744 \uc783\uc740 \uac83 \uac19\uc740 \ub290\ub08c\uc774 \ub4e0 \uc801\uc774 \uc788\ub098\uc694?\n\uc608\uc218\ub2d8\uc740 \uc2a4\uc2a4\ub85c\ub97c "\uae38"\uc774\ub77c\uace0 \ub9d0\uc500\ud558\uc168\uc2b5\ub2c8\ub2e4.\n\uc624\ub298 \uc608\uc218\ub2d8\uc774 \ubcf4\uc5ec\uc8fc\uc2dc\ub294 \uae38\uc744 \ub530\ub77c\uac00\ub294 \uac83\uc5d0 \ub300\ud574 \ubb35\uc0c1\ud574\ubcf4\uc138\uc694.')
B.an8=new A.iB("\ub0b4\uac8c \ub2a5\ub825 \uc8fc\uc2dc\ub294 \uc790","\ub0b4\uac8c \ub2a5\ub825 \uc8fc\uc2dc\ub294 \uc790 \uc548\uc5d0\uc11c\n\ub0b4\uac00 \ubaa8\ub4e0 \uac83\uc744 \ud560 \uc218 \uc788\ub290\ub2c8\ub77c","\ube4c\ub9bd\ubcf4\uc11c 4:13",'"\ub0b4 \ud798\uc73c\ub85c\ub294 \uc548 \ub3fc"\ub77c\uace0 \ub290\ub07c\ub294 \uc77c\uc774 \uc788\ub098\uc694?\n\ubc14\uc6b8\uc740 \uac10\uc625\uc5d0\uc11c\ub3c4 \uc774 \uace0\ubc31\uc744 \ud588\uc2b5\ub2c8\ub2e4.\n\ub0b4 \ub2a5\ub825\uc774 \uc544\ub2cc, \ub2a5\ub825 \uc8fc\uc2dc\ub294 \ubd84\uc744 \uc758\uc9c0\ud558\ub294 \uac83\uc774 \ud575\uc2ec\uc785\ub2c8\ub2e4.')
